/**
 * Entry point for the SVGSketch GitHub Action.
 *
 * Reads Action inputs, globs for `.svgs` files, renders each one to SVG
 * using `@svgsketch/core`, and writes the results next to the sources or
 * into the configured output directory.
 *
 * Outputs:
 *   - `files` : JSON array of rendered SVG paths (relative to workspace)
 *   - `count` : number of files rendered
 */

import * as core from '@actions/core';
import * as glob from '@actions/glob';
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, relative, sep } from 'node:path';

import { parseInputs, type ActionInputs } from './inputs';
import { renderSvgsContent, computeOutputPath } from './render';

/**
 * Convert a platform-native path to a POSIX-style path (forward slashes).
 * `@actions/glob` emits forward slashes but Node's `path.relative` returns
 * platform-native separators — this keeps our output consistent.
 */
function toPosix(p: string): string {
  return sep === '\\' ? p.replace(/\\/g, '/') : p;
}

/**
 * Common base directory for a set of paths, used to strip a shared
 * prefix before mirroring directory structure into the output dir.
 *
 * Implementation: walk each path in parallel, finding the longest
 * shared directory prefix. Returns an empty string when there is no
 * common prefix (e.g. paths on different volumes).
 */
function commonBaseDir(paths: string[]): string {
  if (paths.length === 0) return '';
  if (paths.length === 1) return toPosix(dirname(paths[0]));

  const split = paths.map((p) => toPosix(p).split('/'));
  const first = split[0];
  let commonLength = 0;
  outer: for (let i = 0; i < first.length - 1; i++) {
    for (let j = 1; j < split.length; j++) {
      if (split[j][i] !== first[i]) break outer;
    }
    commonLength = i + 1;
  }
  return first.slice(0, commonLength).join('/');
}

async function run(): Promise<void> {
  // ── Parse inputs ────────────────────────────────────────────────
  let inputs: ActionInputs;
  try {
    inputs = parseInputs((name) => core.getInput(name));
  } catch (err) {
    core.setFailed((err as Error).message);
    return;
  }

  core.info(`Globbing for \`.svgs\` files matching: ${inputs.input}`);

  // ── Glob ────────────────────────────────────────────────────────
  const globber = await glob.create(inputs.input, { followSymbolicLinks: false });
  const matchedRaw = await globber.glob();
  const matched = matchedRaw.filter((p) => p.toLowerCase().endsWith('.svgs'));

  if (matched.length === 0) {
    core.warning(`No \`.svgs\` files matched pattern: ${inputs.input}`);
    core.setOutput('files', '[]');
    core.setOutput('count', '0');
    return;
  }

  core.info(`Found ${matched.length} \`.svgs\` file(s).`);

  const workspace = process.env.GITHUB_WORKSPACE ?? process.cwd();
  const baseDir = commonBaseDir(matched);

  // ── Render each file ────────────────────────────────────────────
  const rendered: string[] = [];
  let errorCount = 0;
  let warningCount = 0;

  for (const sourcePath of matched) {
    const relSource = toPosix(relative(workspace, sourcePath)) || toPosix(sourcePath);
    try {
      const content = await readFile(sourcePath, 'utf-8');

      const result = renderSvgsContent(content, {
        variables: inputs.variables,
        width: inputs.width,
        height: inputs.height,
        background: inputs.background,
      });

      // Surface warnings. parseDocument would have thrown on errors, so
      // a non-empty `errors` list here is unexpected — log it anyway.
      for (const w of result.warnings) {
        warningCount++;
        core.warning(`${relSource} — ${w.path}: ${w.message}`);
      }
      for (const e of result.errors) {
        errorCount++;
        core.error(`${relSource} — ${e.path}: ${e.message}`);
      }

      // Compute the output path and write.
      const posixSource = toPosix(sourcePath);
      const posixBase = toPosix(baseDir);
      const outputPath = computeOutputPath(posixSource, inputs.outputDir, posixBase);
      await mkdir(dirname(outputPath), { recursive: true });
      await writeFile(outputPath, result.svg, 'utf-8');

      const relOut = toPosix(relative(workspace, outputPath)) || toPosix(outputPath);
      rendered.push(relOut);
      core.info(`✓ Rendered ${relSource} → ${relOut}`);
    } catch (err) {
      errorCount++;
      core.error(`✗ Failed to render ${relSource}: ${(err as Error).message}`);
    }
  }

  // ── Outputs ─────────────────────────────────────────────────────
  // Set outputs first — they must land regardless of whether the
  // summary-write call later succeeds (it requires GITHUB_STEP_SUMMARY,
  // which is absent outside Actions runners).
  core.setOutput('files', JSON.stringify(rendered));
  core.setOutput('count', String(rendered.length));

  // ── Summary (best-effort) ───────────────────────────────────────
  try {
    await core.summary
      .addHeading('SVGSketch Render Summary', 2)
      .addRaw(`Rendered **${rendered.length}** / ${matched.length} file(s).`, true)
      .addRaw(`Errors: ${errorCount} • Warnings: ${warningCount}`, true)
      .write({ overwrite: false });
  } catch (err) {
    // Summary requires GITHUB_STEP_SUMMARY; skip silently when it's
    // unavailable (e.g. local invocation for tests or debugging).
    core.debug(`Skipping job summary: ${(err as Error).message}`);
  }

  if (errorCount > 0) {
    core.setFailed(`Rendering failed for ${errorCount} file(s).`);
    return;
  }
  if (inputs.failOnWarnings && warningCount > 0) {
    core.setFailed(`${warningCount} validation warning(s) treated as failures (fail-on-warnings: true).`);
  }
}

run().catch((err) => {
  core.setFailed(`Unhandled error: ${(err as Error).stack ?? (err as Error).message}`);
});
